chapters.teach:
```cpp
int comptePairs(std::vector<int> v) {
    int c = 0;
    for (int x : v) { if (x % 2 == 0) c++; }
    return c;
}
```

chapters.starterCode:
#include <iostream>
#include <vector>
// définis comptePairs ici
int main() {
    std::vector<int> v = {1, 2, 3, 4};
    // cout comptePairs(v)
    return 0;
}

chapters.correction:
#include <iostream>
#include <vector>
int comptePairs(std::vector<int> v) {
    int c = 0;
    for (int x : v) { if (x % 2 == 0) c++; }
    return c;
}
int main() {
    std::vector<int> v = {1, 2, 3, 4};
    std::cout << comptePairs(v) << std::endl;
    return 0;
}

