chapters.teach:
```cpp
int moyenne(std::vector<int> v) {
    int s = 0;
    for (int x : v) { s += x; }
    return s / v.size();
}
```

chapters.starterCode:
#include <iostream>
#include <vector>
// définis moyenne ici
int main() {
    std::vector<int> v = {12, 18, 12};
    // cout moyenne(v)
    return 0;
}

chapters.correction:
#include <iostream>
#include <vector>
int moyenne(std::vector<int> v) {
    int s = 0;
    for (int x : v) { s += x; }
    return s / v.size();
}
int main() {
    std::vector<int> v = {12, 18, 12};
    std::cout << moyenne(v) << std::endl;
    return 0;
}
